namespace UnitTest.Components;

public class DynamicElementTest
{
    [Fact]
    public void Key_OK()
    {
        var context = new BunitContext();
        var cut = context.Render<DynamicElement>(pb =>
        {
            pb.Add(s => s.Key, Guid.NewGuid());
        });

        Assert.Equal("<div></div>", cut.Markup);
    }
}

