namespace UnitTest.Components;

public class DynamicElementTest
{
    [Fact]
    public void Key_OK()
    {
        var context = new BunitContext();
        var cut = context.Render<DynamicElement>(pb =>
        {
            pb.Add(s => s.Key, Guid.NewGuid());
        });

        Assert.Equal("<div></div>", cut.Markup);
    }

    [Fact]
    public void DisposeAsync_NotImplement()
    {
        var element = new DynamicElement();

        Assert.False(element is IAsyncDisposable);
    }

    [Fact]
    public void TouchStartEnd_Ok()
    {
        var touchStart = false;
        var touchEnd = false;
        var context = new BunitContext();
        var cut = context.Render<DynamicElement>(pb =>
        {
            pb.Add(s => s.OnTouchStart, _ =>
            {
                touchStart = true;
                return Task.CompletedTask;
            });
            pb.Add(s => s.OnTouchEnd, _ =>
            {
                touchEnd = true;
                return Task.CompletedTask;
            });
        });

        var element = cut.Find("div");
        element.TouchStart(new TouchEventArgs());
        element.TouchEnd(new TouchEventArgs());

        Assert.True(touchStart);
        Assert.True(touchEnd);
    }
}

